  ('aboriginal-7be5e2bb-moex-00024', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '關於國家賠償法之敘述，下列何者錯誤？', '["人民主張因違法行政處分而發生國家賠償訴訟時，經行政法院裁判確定該處分違法，普通法院 仍應審查是否具備其他賠償之要件", "管理機關對自然公物內之設施管理欠缺，致人民生命、身體或財產受損害者，構成國家賠償責任", "行政機關依國家賠償法為賠償後，得對實際應負最終賠償責任之機關求償", "國家賠償法所稱之行使公權力，係指公務員行使統治權作用之公法行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
  ('aboriginal-7be5e2bb-moex-00025', 'aboriginal-7be5e2bb', 'aboriginal-7be5e2bb-moex-114-3082b5f1', 'sub-aboriginal-7be5e2bb-01', NULL, 'single_choice', '下列何種情況應給予損失補償？', '["地方政府派員警驅趕閒置國有建築內長年聚集飲酒喧嘩之民眾，因衝突而違法使用警械致民眾 受傷", "消防車為搶救火災而駛入狹小巷弄，致路邊白線內側休旅車受損", "員警執行解散集會命令時，與集會民眾發生口角，員警憤而壓制民眾，造成民眾腦震盪住院治療", "颱風登陸前夕，地方政府於媒體中公告水門即將關閉，儘速移走堤防外之停車，民眾自信認為 不至於淹水而未移車，導致車輛泡水"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "507", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "體育行政"}'::jsonb, NULL),
